function e(e,t,n=5){let r=new Map;for(let t of e){let e=r.get(t.source);e?e.push(t.target):r.set(t.source,[t.target])}let i=new Map([[t,0]]),a=[t];for(let e=1;e<=n&&a.length>0;e++){let t=[];for(let n of a)for(let a of r.get(n)??[])i.has(a)||(i.set(a,e),t.push(a));a=t}return i}function t(e){return Math.max(.08,.32-.06*(e-1))}function n(e){let t=new Map;for(let n of e){let e=t.get(n.depth);e?e.push(n):t.set(n.depth,[n])}return[...t.entries()].sort((e,t)=>e[0]-t[0])}export{n,t as r,e as t};